// Star chart view (constellation lines, equatorial grid)
core.clear("starchart");

// Deep space view (no planets, suitable for distant objects)
core.clear("deepspace");

// Display in galactic coordinates
core.clear("galactic");

// Display in supergalactic coordinates
core.clear("supergalactic");

// Show star labels
core.setStelProperty("Stars.flagLabels", true);

// Change night sky color
core.setStelProperty("color.night_color", "#1a0a2e");

// Set star magnitude limit
core.setStelProperty("Stars.labelsAmount", 5);

// Show planet orbits
core.setStelProperty("SolarSystem.flagOrbits", true);

// Show atmosphere
core.setStelProperty("LandscapeMgr.setFlagAtmosphere", true);

// Get list of all properties
var allProps = core.getPropertyList();
core.debug("Total properties: " + allProps.length);

var starsVisible = core.getStelProperty("Stars.flagStars");
core.debug("Stars visible: " + starsVisible);

var bortle = core.getStelProperty("BortleScaleIndex");
core.debug("Bortle index: " + bortle);

var props = core.getPropertyList();
core.debug("Total properties: " + props.length);

// Search for specific properties
var starProps = props.filter(p => p.includes("Star"));
core.debug("Star properties: " + starProps.length);

// Dark rural sky
core.setBortleScaleIndex(3);

// Large city sky
core.setBortleScaleIndex(8);

var bortle = core.getBortleScaleIndex();
core.debug("Current Bortle scale: " + bortle);

var bortle = core.getBortleScaleIndex();
var desc = "";
if(bortle <= 2) desc = "Very dark sky - excellent for observation";
else if(bortle <= 4) desc = "Rural sky - good for observation";
else if(bortle <= 6) desc = "Suburban sky - limited observation";
else desc = "Urban sky - severe light pollution";
core.debug(desc);

// Calculate apparent altitude with refraction
var trueAlt = 10.0;
var apparentAlt = core.refraction(trueAlt, false);
core.debug("True altitude: " + trueAlt + "° → Apparent: " + apparentAlt.toFixed(2) + "°");

// Remove refraction effect (to calculate true position)
var observedAlt = 5.0;
var corrected = core.refraction(observedAlt, true);
core.debug("Observed altitude: " + observedAlt + "° → Corrected: " + corrected.toFixed(2) + "°");

// Find Sun's position on screen
var sunInfo = core.getObjectInfo("Sun");
var screenPos = core.getScreenXYFromAltAzi(sunInfo["altitude"], sunInfo["azimuth"]);
core.debug("Sun position on screen: (" + screenPos["x"] + ", " + screenPos["y"] + ")");

var lang = core.getAppLanguage();
core.debug("Current language: " + lang);

// Change language
// core.setAppLanguage("ar"); // Arabic
// core.setAppLanguage("fr"); // French
// core.setAppLanguage("de"); // German

var hello = core.translate("Hello");
var welcome = core.translate("Welcome to Stellarium");
core.debug(welcome);

// Check if Satellites plugin is available
if(core.isModuleLoaded("Satellites")) {
    core.setStelProperty("Satellites.flagLabels", true);
    core.debug("Satellites plugin active");
} else {
    core.debug("Satellites plugin not loaded - skipping");
}

// Check Exoplanets plugin
if(core.isModuleLoaded("Exoplanets")) {
    core.debug("Exoplanets plugin available");
}

// Check operating system platform
var platform = core.getPlatformName();
core.debug("Operating system: " + platform);

var os = core.getPlatformName();
core.debug("Operating system: " + os);
if(os === "Windows") {
    // Windows-specific code
} else if(os === "Linux") {
    // Linux-specific code
}

var username = core.getEnv("USERNAME");
var home = core.getEnv("HOME");
var path = core.getEnv("PATH");
core.debug("User: " + username);
core.debug("Home directory: " + home);

core.say("Welcome to Stellarium");
core.say("Current time is " + core.getDate("local"));

// Speak selected object coordinates
core.selectObjectByName("Mars");
var info = core.getSelectedObjectInfo();
core.say("Mars is currently at " + info["azimuth"].toFixed(0) + " degrees azimuth");

core.setDisplayMaxLuminance(200);
var lum = core.getDisplayMaxLuminance();
core.debug("Max luminance: " + lum + " cd/m²");

core.setDisplayGamma(2.4); // Higher contrast
var gamma = core.getDisplayGamma();
core.debug("Gamma: " + gamma);

if(core.useQtScript()) {
    core.debug("Running on QtScript");
} else {
    core.debug("Running on QML");
}
